namespace BlazorApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = "";
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;

    private static readonly string[] SampleMessages =
    [
        "Your build succeeded.",
        "New comment on your pull request.",
        "Deployment to production completed.",
        "Disk usage above 80%.",
        "A teammate mentioned you in a review.",
        "Scheduled maintenance tonight at 11 PM.",
        "New security advisory published.",
        "Pipeline run failed — check logs.",
    ];

    /// <summary>Returns a batch of initial notifications.</summary>
    public Task<List<NotificationItem>> GetInitialNotificationsAsync()
    {
        var items = new List<NotificationItem>();
        for (var i = 0; i < 3; i++)
        {
            items.Add(MakeNotification());
        }
        return Task.FromResult(items);
    }

    /// <summary>Simulates polling — returns 0-1 new notifications per call.</summary>
    public Task<List<NotificationItem>> CheckForNewNotificationsAsync()
    {
        var items = new List<NotificationItem>();
        if (Random.Shared.NextDouble() > 0.4)
        {
            items.Add(MakeNotification());
        }
        return Task.FromResult(items);
    }

    private NotificationItem MakeNotification()
    {
        var id = Interlocked.Increment(ref _nextId);
        return new NotificationItem
        {
            Id = id,
            Message = SampleMessages[id % SampleMessages.Length],
            Timestamp = DateTime.Now
        };
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using BlazorApp.Services
@inject NotificationService Svc
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("T")</small>
            </li>
        }
    </ul>
}

@code {
    [PersistentState]
    public List<NotificationItem>? Notifications { get; set; }

    private List<NotificationItem> notifications = new();
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        Notifications ??= await Svc.GetInitialNotificationsAsync();
        notifications = Notifications;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollLoopAsync(_cts.Token);
        }
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(5000, ct);

            var fresh = await Svc.CheckForNewNotificationsAsync();
            if (fresh.Count > 0)
            {
                notifications.InsertRange(0, fresh);
                Notifications = notifications;
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

